#include "db.h"

#include <sqlite3.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

static sqlite3 *db = NULL;

static char *json_escape(const char *s) {
    if (!s) s = "";
    size_t len = 0;
    for (const unsigned char *p = (const unsigned char *)s; *p; p++) {
        switch (*p) {
            case '"':
            case '\\':
                len += 2;
                break;
            case '\b':
            case '\f':
            case '\n':
            case '\r':
            case '\t':
                len += 2;
                break;
            default:
                if (*p < 0x20)
                    len += 6; // \u00XX
                else
                    len += 1;
        }
    }

    char *out = malloc(len + 1);
    if (!out) return NULL;

    char *o = out;
    for (const unsigned char *p = (const unsigned char *)s; *p; p++) {
        switch (*p) {
            case '"': *o++ = '\\'; *o++ = '"'; break;
            case '\\': *o++ = '\\'; *o++ = '\\'; break;
            case '\b': *o++ = '\\'; *o++ = 'b'; break;
            case '\f': *o++ = '\\'; *o++ = 'f'; break;
            case '\n': *o++ = '\\'; *o++ = 'n'; break;
            case '\r': *o++ = '\\'; *o++ = 'r'; break;
            case '\t': *o++ = '\\'; *o++ = 't'; break;
            default:
                if (*p < 0x20) {
                    sprintf(o, "\\u%04x", (unsigned int)*p);
                    o += 6;
                } else {
                    *o++ = (char)*p;
                }
        }
    }
    *o = '\0';
    return out;
}

int init_db(const char *path) {
    if (sqlite3_open_v2(path, &db,
                        SQLITE_OPEN_READWRITE | SQLITE_OPEN_CREATE | SQLITE_OPEN_FULLMUTEX,
                        NULL) != SQLITE_OK) {
        fprintf(stderr, "Cannot open database: %s\n", sqlite3_errmsg(db));
        return -1;
    }

    sqlite3_busy_timeout(db, 5000);

    char *err_msg = NULL;
    sqlite3_exec(db, "PRAGMA journal_mode=WAL;", NULL, NULL, &err_msg);
    if (err_msg) sqlite3_free(err_msg);
    err_msg = NULL;
    sqlite3_exec(db, "PRAGMA synchronous=NORMAL;", NULL, NULL, &err_msg);
    if (err_msg) sqlite3_free(err_msg);

    const char *sql =
        "CREATE TABLE IF NOT EXISTS notes ("
        "id INTEGER PRIMARY KEY AUTOINCREMENT,"
        "title TEXT NOT NULL,"
        "content TEXT NOT NULL"
        ");";

    if (sqlite3_exec(db, sql, NULL, NULL, &err_msg) != SQLITE_OK) {
        fprintf(stderr, "SQL error: %s\n", err_msg);
        sqlite3_free(err_msg);
        return -1;
    }

    return 0;
}

void close_db(void) {
    if (db) sqlite3_close(db);
    db = NULL;
}

int create_note(const char *title, const char *content) {
    if (!db) return -1;

    sqlite3_stmt *stmt = NULL;
    const char *sql = "INSERT INTO notes(title, content) VALUES(?, ?);";

    if (sqlite3_prepare_v2(db, sql, -1, &stmt, NULL) != SQLITE_OK) return -1;

    sqlite3_bind_text(stmt, 1, title ? title : "", -1, SQLITE_TRANSIENT);
    sqlite3_bind_text(stmt, 2, content ? content : "", -1, SQLITE_TRANSIENT);

    int rc = sqlite3_step(stmt);
    sqlite3_finalize(stmt);
    if (rc != SQLITE_DONE) return -1;

    return (int)sqlite3_last_insert_rowid(db);
}

static int append_str(char **buf, size_t *cap, size_t *len, const char *s) {
    size_t add = strlen(s);
    if (*len + add + 1 > *cap) {
        size_t ncap = (*cap == 0) ? 256 : *cap;
        while (*len + add + 1 > ncap) ncap *= 2;
        char *nbuf = realloc(*buf, ncap);
        if (!nbuf) return -1;
        *buf = nbuf;
        *cap = ncap;
    }
    memcpy(*buf + *len, s, add);
    *len += add;
    (*buf)[*len] = '\0';
    return 0;
}

char *get_notes_paginated_json(int limit, int offset) {
    if (!db) return NULL;

    const char *sql = "SELECT id, title, content FROM notes ORDER BY id LIMIT ? OFFSET ?;";
    sqlite3_stmt *stmt = NULL;
    if (sqlite3_prepare_v2(db, sql, -1, &stmt, NULL) != SQLITE_OK) return NULL;
    sqlite3_bind_int(stmt, 1, limit);
    sqlite3_bind_int(stmt, 2, offset);

    char *out = NULL;
    size_t cap = 0, len = 0;
    if (append_str(&out, &cap, &len, "[") != 0) {
        sqlite3_finalize(stmt);
        return NULL;
    }

    int first = 1;
    while (sqlite3_step(stmt) == SQLITE_ROW) {
        int id = sqlite3_column_int(stmt, 0);
        const char *title = (const char *)sqlite3_column_text(stmt, 1);
        const char *content = (const char *)sqlite3_column_text(stmt, 2);

        char *et = json_escape(title);
        char *ec = json_escape(content);
        if (!et || !ec) {
