            free(out);
            sqlite3_finalize(stmt);
            return NULL;
        }

        char item[64];
        snprintf(item, sizeof(item), "%s{\"id\":%d,\"title\":\"", first ? "" : ",", id);
        first = 0;

        if (append_str(&out, &cap, &len, item) != 0 ||
            append_str(&out, &cap, &len, et) != 0 ||
            append_str(&out, &cap, &len, "\",\"content\":\"") != 0 ||
            append_str(&out, &cap, &len, ec) != 0 ||
            append_str(&out, &cap, &len, "\"}") != 0) {
            free(et); free(ec);
            free(out);
            sqlite3_finalize(stmt);
            return NULL;
        }

        free(et);
        free(ec);
    }

    sqlite3_finalize(stmt);

    if (append_str(&out, &cap, &len, "]") != 0) {
        free(out);
        return NULL;
    }

    return out;
}

