static enum MHD_Result send_json_with_headers(struct MHD_Connection *connection,
                                             const char *body,
                                             unsigned int status_code,
                                             const char *extra_header_name,
                                             const char *extra_header_value) {
    struct MHD_Response *response = MHD_create_response_from_buffer(
        strlen(body), (void *)body, MHD_RESPMEM_MUST_COPY);

    MHD_add_response_header(response, "Content-Type", "application/json");
    MHD_add_response_header(response, "Access-Control-Allow-Origin", "*");
    MHD_add_response_header(response, "Access-Control-Allow-Methods",
                            "GET, POST, PUT, DELETE, OPTIONS");
    MHD_add_response_header(response, "Access-Control-Allow-Headers",
                            "Content-Type, X-API-Key");

    if (extra_header_name && extra_header_value)
        MHD_add_response_header(response, extra_header_name, extra_header_value);

    enum MHD_Result ret = MHD_queue_response(connection, status_code, response);
    MHD_destroy_response(response);
    return ret;
}

static enum MHD_Result send_json(struct MHD_Connection *connection,
                                const char *body,
                                unsigned int status_code) {
    return send_json_with_headers(connection, body, status_code, NULL, NULL);
}

static enum MHD_Result send_json_total(struct MHD_Connection *connection,
