                    len += 6; // \u00XX
                else
                    len += 1;
        }
    }

    char *out = malloc(len + 1);
    if (!out) return NULL;

    char *o = out;
    for (const unsigned char *p = (const unsigned char *)s; *p; p++) {
        switch (*p) {
            case '"': *o++ = '\\'; *o++ = '"'; break;
            case '\\': *o++ = '\\'; *o++ = '\\'; break;
