static enum MHD_Result send_json_with_headers(struct MHD_Connection *connection,
                                             const char *body,
                                             unsigned int status_code,
                                             const char *extra_header_name,
                                             const char *extra_header_value) {
    struct MHD_Response *response = MHD_create_response_from_buffer(
        strlen(body), (void *)body, MHD_RESPMEM_MUST_COPY);

    MHD_add_response_header(response, "Content-Type", "application/json");
    MHD_add_response_header(response, "Access-Control-Allow-Origin", "*");
    MHD_add_response_header(response, "Access-Control-Allow-Methods",
                            "GET, POST, PUT, DELETE, OPTIONS");
    MHD_add_response_header(response, "Access-Control-Allow-Headers",
                            "Content-Type, X-API-Key");

    if (extra_header_name && extra_header_value)
        MHD_add_response_header(response, extra_header_name, extra_header_value);

    enum MHD_Result ret = MHD_queue_response(connection, status_code, response);
    MHD_destroy_response(response);
    return ret;
}

static enum MHD_Result send_json(struct MHD_Connection *connection,
                                const char *body,
                                unsigned int status_code) {
    return send_json_with_headers(connection, body, status_code, NULL, NULL);
}

static enum MHD_Result send_json_total(struct MHD_Connection *connection,
                                      const char *body,
                                      unsigned int status_code,
                                      int total) {
    char count_str[32];
    snprintf(count_str, sizeof(count_str), "%d", total);
    return send_json_with_headers(connection, body, status_code, "X-Total-Count", count_str);
}

static int parse_int(const char *s, int *out) {
    if (!s || !*s) return 0;
    char *end = NULL;
    long v = strtol(s, &end, 10);
    if (end == s || *end != '\0') return 0;
    if (v < 0) v = 0;
    if (v > 1000000000L) v = 1000000000L;
    *out = (int)v;
    return 1;
}

static void skip_ws(const char **p) {
    while (**p && isspace((unsigned char)**p)) (*p)++;
}

static int parse_json_string(const char **p, char **out) {
    // expects opening quote
    if (**p != '"') return 0;
    (*p)++;

    size_t cap = 64, len = 0;
    char *buf = malloc(cap);
    if (!buf) return 0;

    while (**p) {
        unsigned char c = (unsigned char)**p;
        if (c == '"') {
            (*p)++;
            buf[len] = '\0';
            *out = buf;
            return 1;
        }
        if (c == '\\') {
            (*p)++;
            c = (unsigned char)**p;
            if (!c) break;
            switch (c) {
                case '"': c = '"'; break;
                case '\\': c = '\\'; break;
                case '/': c = '/'; break;
                case 'b': c = '\b'; break;
                case 'f': c = '\f'; break;
                case 'n': c = '\n'; break;
                case 'r': c = '\r'; break;
                case 't': c = '\t'; break;
                case 'u':
                    // minimal: keep as literal 'u' sequence unsupported -> reject
                    free(buf);
                    return 0;
                default:
                    // unknown escape
                    free(buf);
                    return 0;
            }
            (*p)++;
        } else {
            (*p)++;
        }

        if (len + 2 > cap) {
            cap *= 2;
            char *nb = realloc(buf, cap);
            if (!nb) {
                free(buf);
                return 0;
            }
            buf = nb;
        }
        buf[len++] = (char)c;
    }

    free(buf);
    return 0;
}

static int json_get_string_field(const char *json, const char *field, char **out) {
    // Very small extractor: finds "field" : "value" with optional whitespace.
    // Rejects non-string values.
    char needle[128];
    snprintf(needle, sizeof(needle), "\"%s\"", field);
    const char *p = strstr(json, needle);
    if (!p) return 0;
    p += strlen(needle);
    skip_ws(&p);
    if (*p != ':') return 0;
    p++;
    skip_ws(&p);
    if (*p != '"') return 0;
    return parse_json_string(&p, out);
}

static int is_blank_title(const char *s) {
    if (!s) return 1;
    const char *p = s;
    while (*p) {
        if (!isspace((unsigned char)*p)) return 0;
        p++;
    }
    return 1;
}

static int parse_id_from_url(const char *url, int *out_id) {
    const char *prefix = "/api/notes/";
    size_t n = strlen(prefix);
    if (strncmp(url, prefix, n) != 0) return 0;
    const char *idstr = url + n;
    if (*idstr == '\0') return 0;
    // disallow trailing slash
    if (strchr(idstr, '/')) return 0;
    return parse_int(idstr, out_id);
}

static enum MHD_Result ensure_connection_info(void **con_cls) {
    if (*con_cls) return MHD_YES;
    struct connection_info *ci = calloc(1, sizeof(*ci));
    if (!ci) return MHD_NO;
    ci->data = NULL;
    ci->data_size = 0;
    *con_cls = ci;
    return MHD_YES;
}

static enum MHD_Result handle_post_put_body(struct MHD_Connection *connection,
                                           const char *method,
                                           const char *url,
                                           const char *upload_data,
                                           size_t *upload_data_size,
                                           void **con_cls) {
    if (ensure_connection_info(con_cls) != MHD_YES) return MHD_NO;
    struct connection_info *ci = (struct connection_info *)(*con_cls);

    if (*upload_data_size != 0) {
        // enforce body size limit
        if (ci->data_size + *upload_data_size > NOTES_MAX_BODY_BYTES) {
            *upload_data_size = 0;
            return send_json(connection, "{\"error\":\"payload too large\"}", MHD_HTTP_PAYLOAD_TOO_LARGE);
        }

        char *nb = realloc(ci->data, ci->data_size + *upload_data_size + 1);
        if (!nb) {
            *upload_data_size = 0;
            return MHD_NO;
        }
        ci->data = nb;
        memcpy(ci->data + ci->data_size, upload_data, *upload_data_size);
        ci->data_size += *upload_data_size;
        ci->data[ci->data_size] = '\0';
        *upload_data_size = 0;
        return MHD_YES;
    }

    // upload finished
    const char *body = ci->data ? ci->data : "";

    char *title = NULL;
    char *content = NULL;
    int has_title = json_get_string_field(body, "title", &title);
    (void)json_get_string_field(body, "content", &content); // optional

    if (!has_title || is_blank_title(title)) {
        free(title);
        free(content);
        return send_json(connection, "{\"error\":\"bad request\"}", MHD_HTTP_BAD_REQUEST);
    }

    if (strcmp(method, "POST") == 0 && strcmp(url, "/api/notes") == 0) {
        int id = create_note(title, content ? content : "");
        if (id < 0) {
            free(title);
            free(content);
            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        }
        char *saved = get_note_json(id);
        free(title);
        free(content);
        if (!saved) return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        enum MHD_Result r = send_json(connection, saved, MHD_HTTP_CREATED);
        free(saved);
        return r;
    }

    if (strcmp(method, "PUT") == 0) {
        int id = 0;
        if (!parse_id_from_url(url, &id)) {
            free(title);
            free(content);
            return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        }
        if (!note_exists(id)) {
            free(title);
            free(content);
            return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        }
        if (!update_note(id, title, content ? content : "")) {
            free(title);
            free(content);
            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        }
        char *saved = get_note_json(id);
        free(title);
        free(content);
        if (!saved) return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        enum MHD_Result r = send_json(connection, saved, MHD_HTTP_OK);
        free(saved);
        return r;
    }

    free(title);
    free(content);
    return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
}

enum MHD_Result route_request(struct MHD_Connection *connection, const char *url,
                              const char *method, const char *upload_data,
                              size_t *upload_data_size, void **con_cls) {
    // CORS preflight
    if (strcmp(method, "OPTIONS") == 0)
        return send_json(connection, "", MHD_HTTP_OK);

    // Collection GET
    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "GET") == 0) {
        int limit = NOTES_DEFAULT_PAGE_SIZE;
        int offset = 0;

        const char *q_limit = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "limit");
        const char *q_offset = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "offset");

        if (q_limit) parse_int(q_limit, &limit);
        if (q_offset) parse_int(q_offset, &offset);
        if (limit <= 0) limit = NOTES_DEFAULT_PAGE_SIZE;
        if (limit > NOTES_MAX_PAGE_SIZE) limit = NOTES_MAX_PAGE_SIZE;
        if (offset < 0) offset = 0;

        int total = get_total_notes_count();
        char *json = get_notes_paginated_json(limit, offset);
        if (!json) return send_json_total(connection, "[]", MHD_HTTP_OK, total);
        enum MHD_Result r = send_json_total(connection, json, MHD_HTTP_OK, total);
        free(json);
        return r;
    }

    // Item GET
    int id = 0;
    if (parse_id_from_url(url, &id) && strcmp(method, "GET") == 0) {
        char *json = get_note_json(id);
        if (!json) return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        enum MHD_Result r = send_json(connection, json, MHD_HTTP_OK);
        free(json);
        return r;
    }

    // POST requires API key
    if (strcmp(method, "POST") == 0 && strcmp(url, "/api/notes") == 0) {
        if (!api_key_valid(connection))
            return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
        return handle_post_put_body(connection, method, url, upload_data, upload_data_size, con_cls);
    }

    // PUT requires API key
    if (strcmp(method, "PUT") == 0 && strncmp(url, "/api/notes/", 11) == 0) {
        if (!api_key_valid(connection))
            return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
        return handle_post_put_body(connection, method, url, upload_data, upload_data_size, con_cls);
    }

    // DELETE requires API key
    if (strcmp(method, "DELETE") == 0 && parse_id_from_url(url, &id)) {
        if (!api_key_valid(connection))
            return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
        if (!note_exists(id))
            return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        if (!delete_note(id))
            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        return send_json(connection, "{\"status\":\"deleted\"}", MHD_HTTP_OK);
    }

    return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
}
