static sqlite3 *db = NULL;

static char *json_escape(const char *s) {
    if (!s) s = "";
    size_t len = 0;
    for (const unsigned char *p = (const unsigned char *)s; *p; p++) {
        switch (*p) {
            case '"':
            case '\\':
                len += 2;
                break;
            case '\b':
            case '\f':
            case '\n':
            case '\r':
            case '\t':
                len += 2;
                break;
            default:
                if (*p < 0x20)
                    len += 6; // \u00XX
                else
                    len += 1;
        }
    }

    char *out = malloc(len + 1);
    if (!out) return NULL;

    char *o = out;
    for (const unsigned char *p = (const unsigned char *)s; *p; p++) {
        switch (*p) {
            case '"': *o++ = '\\'; *o++ = '"'; break;
            case '\\': *o++ = '\\'; *o++ = '\\'; break;
            case '\b': *o++ = '\\'; *o++ = 'b'; break;
            case '\f': *o++ = '\\'; *o++ = 'f'; break;
            case '\n': *o++ = '\\'; *o++ = 'n'; break;
