            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        return send_json(connection, "{\"status\":\"deleted\"}", MHD_HTTP_OK);
    }

    return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
}
