    enum MHD_Result ret = MHD_queue_response(connection, status_code, response);
    MHD_destroy_response(response);
    return ret;
}

static enum MHD_Result send_json(struct MHD_Connection *connection,
                                const char *body,
                                unsigned int status_code) {
    return send_json_with_headers(connection, body, status_code, NULL, NULL);
}

static enum MHD_Result send_json_total(struct MHD_Connection *connection,
                                      const char *body,
                                      unsigned int status_code,
                                      int total) {
    char count_str[32];
    snprintf(count_str, sizeof(count_str), "%d", total);
    return send_json_with_headers(connection, body, status_code, "X-Total-Count", count_str);
}

static int parse_int(const char *s, int *out) {
    if (!s || !*s) return 0;
    char *end = NULL;
    long v = strtol(s, &end, 10);
    if (end == s || *end != '\0') return 0;
    if (v < 0) v = 0;
    if (v > 1000000000L) v = 1000000000L;
    *out = (int)v;
    return 1;
}

static void skip_ws(const char **p) {
    while (**p && isspace((unsigned char)**p)) (*p)++;
}

static int parse_json_string(const char **p, char **out) {
    if (**p != '"') return 0;
    (*p)++;

    size_t cap = 64, len = 0;
    char *buf = malloc(cap);
    if (!buf) return 0;

    while (**p) {
        unsigned char c = (unsigned char)**p;
        if (c == '"') {
            (*p)++;
            buf[len] = '\0';
            *out = buf;
            return 1;
        }

        if (c == '\\') {
            (*p)++;
            c = (unsigned char)**p;
            if (!c) break;
            switch (c) {
                case '"': c = '"'; break;
                case '\\': c = '\\'; break;
                case '/': c = '/'; break;
                case 'b': c = '\b'; break;
                case 'f': c = '\f'; break;
                case 'n': c = '\n'; break;
                case 'r': c = '\r'; break;
                case 't': c = '\t'; break;
                case 'u':
                    free(buf);
                    return 0;
                default:
                    free(buf);
                    return 0;
            }
            (*p)++;
        } else {
            (*p)++;
        }

        if (len + 2 > cap) {
            cap *= 2;
            char *nb = realloc(buf, cap);
            if (!nb) {
                free(buf);
                return 0;
            }
            buf = nb;
        }
        buf[len++] = (char)c;
    }

    free(buf);
    return 0;
}

static int json_get_string_field(const char *json, const char *field, char **out) {
    char needle[128];
    snprintf(needle, sizeof(needle), "\"%s\"", field);
    const char *p = strstr(json, needle);
    if (!p) return 0;
    p += strlen(needle);
    skip_ws(&p);
    if (*p != ':') return 0;
    p++;
    skip_ws(&p);
    if (*p != '"') return 0;
    return parse_json_string(&p, out);
}

static int is_blank_title(const char *s) {
    if (!s) return 1;
    const char *p = s;
    while (*p) {
        if (!isspace((unsigned char)*p)) return 0;
        p++;
    }
    return 1;
}

static int parse_id_from_url(const char *url, int *out_id) {
    const char *prefix = "/api/notes/";
    size_t n = strlen(prefix);
    if (strncmp(url, prefix, n) != 0) return 0;
    const char *idstr = url + n;
    if (*idstr == '\0') return 0;
    if (strchr(idstr, '/')) return 0;
    return parse_int(idstr, out_id);
}

static enum MHD_Result init_con_info(void **con_cls) {
    struct connection_info *ci = calloc(1, sizeof(*ci));
    if (!ci) return MHD_NO;
    *con_cls = ci;
    return MHD_YES;
}

static enum MHD_Result handle_post_put_body(struct MHD_Connection *connection,
                                           const char *method,
                                           const char *url,
                                           const char *upload_data,
                                           size_t *upload_data_size,
                                           void **con_cls) {
    struct connection_info *ci = (struct connection_info *)(*con_cls);
    if (!ci) return MHD_NO;

    if (*upload_data_size != 0) {
        if (ci->data_size + *upload_data_size > NOTES_MAX_BODY_BYTES) {
            *upload_data_size = 0;
            return send_json(connection, "{\"error\":\"payload too large\"}", MHD_HTTP_PAYLOAD_TOO_LARGE);
        }
        char *nb = realloc(ci->data, ci->data_size + *upload_data_size + 1);
        if (!nb) {
